const src = String($json.data ?? $json.body ?? $json.html ?? $json.response ?? '');

if (!src || src.length < 200) {
  throw new Error('Sayfa HTML icerigi bos geldi.');
}

function removeNoise(html) {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<svg[\s\S]*?<\/svg>/gi, ' ');
}

function decodeEntities(str) {
  const named = {
    nbsp: ' ',
    amp: '&',
    quot: '"',
    apos: "'",
    lt: '<',
    gt: '>'
  };

  let out = str.replace(/&([a-zA-Z]+);/g, (m, n) => {
    const k = n.toLowerCase();
    return Object.prototype.hasOwnProperty.call(named, k) ? named[k] : ' ';
  });

  out = out.replace(/&#x([0-9a-fA-F]+);/g, (m, h) => {
    const cp = parseInt(h, 16);
    return Number.isFinite(cp) ? String.fromCodePoint(cp) : ' ';
  });

  out = out.replace(/&#([0-9]+);/g, (m, d) => {
    const cp = parseInt(d, 10);
    return Number.isFinite(cp) ? String.fromCodePoint(cp) : ' ';
  });

  return out;
}

function stripTags(html) {
  return html.replace(/<[^>]+>/g, ' ');
}

function normalize(s) {
  return s
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

function pickMainBlock(html) {
  const base = removeNoise(html);
  const body = base.match(/<body\b[\s\S]*?<\/body>/i);
  const scope = body ? body[0] : base;

  const patterns = [
    /<main\b[\s\S]*?<\/main>/gi,
    /<article\b[\s\S]*?<\/article>/gi,
    /<section\b[^>]*(product|urun|detay|detail|icerik|content|entry|post)[^>]*>[\s\S]*?<\/section>/gi
  ];

  const blocks = [];
  for (const p of patterns) {
    const found = scope.match(p) || [];
    for (const f of found) blocks.push(f);
  }

  if (!blocks.length) return scope;
  blocks.sort((a, b) => b.length - a.length);
  return blocks[0];
}

const titleMatch = src.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const pageTitleRaw = titleMatch ? stripTags(titleMatch[1]) : '';
const pageTitle = decodeEntities(pageTitleRaw).replace(/\s+/g, ' ').trim().split('|')[0].trim();

const mainHtml = pickMainBlock(src);
let text = decodeEntities(stripTags(mainHtml));

text = text
  .replace(/\b(Anasayfa|Hizmetlerimiz|Urunlerimiz|Ürünlerimiz|Haberler|Kurumsal|Hakkimizda|Hakkımızda|Kariyer|Partnerimiz Olun|Iletisim|İletişim|Cerez Politikasi|Çerez Politikası|Sosyal Medya|Uygulama Magazasi|Uygulama Mağazası)\b/gi, ' ')
  .replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, ' ')
  .replace(/(?:\+?90|0)?\s*\(?\d{3}\)?\s*\d{3}\s*\d{2}\s*\d{2}/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const stopWords = new Set([
  've', 'ile', 'icin', 'yeni', 'nesil', 'deneyim', 'cozum', 'platform',
  'creamobile', 'mobil', 'uygulama', 'gelistirme', 'ltd', 'sti'
]);

const titleTerms = normalize(pageTitle)
  .split(/[^a-z0-9]+/)
  .filter(w => w.length >= 3 && !stopWords.has(w));

const focusTerms = [...new Set(titleTerms)].slice(0, 8);

const sentences = text.match(/[^.!?]+[.!?]?/g) || [text];
if (focusTerms.length && sentences.length > 5) {
  const keep = new Set();

  for (let i = 0; i < sentences.length; i++) {
    const s = normalize(sentences[i]);
    let score = 0;
    for (const t of focusTerms) {
      if (s.includes(t)) score++;
    }
    if (score > 0) {
      keep.add(i);
      keep.add(i + 1);
    }
  }

  const picked = [...keep]
    .sort((a, b) => a - b)
    .filter(i => i >= 0 && i < sentences.length)
    .map(i => sentences[i].trim())
    .filter(Boolean);

  if (picked.length >= 3) {
    text = picked.join(' ');
  }
}

const endMarkers = ['bize ulasin', 'ofislerimiz', 'baglantilar', 'copyright'];
const low = normalize(text);
let cut = -1;
for (const m of endMarkers) {
  const idx = low.indexOf(m);
  if (idx !== -1) cut = cut === -1 ? idx : Math.min(cut, idx);
}
if (cut > 0) text = text.slice(0, cut).trim();

if (!text || text.length < 350) {
  throw new Error('Urun icerigi yeterince ayrisamadi. Sayfa yapisi farkli olabilir.');
}

return [
  {
    json: {
      page_title: pageTitle,
      focus_terms: focusTerms,
      cleaned_text: text.slice(0, 9000)
    }
  }
];

const item = $input.first().json;
const raw = String(item.text || item.output || "").trim();

function readJson(str) {
  try {
    return JSON.parse(str);
  } catch (e) {
    const s = str.indexOf("{");
    const t = str.lastIndexOf("}");
    if (s === -1 || t === -1 || t <= s) {
      throw new Error("AI1 gecerli JSON dondurmedi.");
    }
    return JSON.parse(str.slice(s, t + 1));
  }
}

const data = readJson(raw);

if (!data.product_context) {
  throw new Error("AI1: product_context eksik.");
}

if (!Array.isArray(data.customer_segments) || data.customer_segments.length < 6) {
  throw new Error("AI1: customer_segments yetersiz.");
}

for (const seg of data.customer_segments) {
  if (!seg || !Array.isArray(seg.must_keywords) || seg.must_keywords.length < 3) {
    throw new Error("AI1: Her segmentte en az 3 must_keywords olmali.");
  }
}

return [{ json: data }];

const raw = (($json.text ?? $json.output ?? '') + '').trim();

function parseJson(str) {
  try {
    return JSON.parse(str);
  } catch {
    const s = str.indexOf('{');
    const t = str.lastIndexOf('}');
    if (s < 0 || t < 0 || t <= s) throw new Error('AI2 gecerli JSON donmedi');
    return JSON.parse(str.slice(s, t + 1));
  }
}

function normTr(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/ı/g, 'i')
    .replace(/ğ/g, 'g')
    .replace(/ü/g, 'u')
    .replace(/ş/g, 's')
    .replace(/ö/g, 'o')
    .replace(/ç/g, 'c')
    .replace(/\s+/g, ' ')
    .trim();
}

function esc(s) {
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

const data = parseJson(raw);
const arr = Array.isArray(data.queries) ? data.queries : [];
if (!arr.length) throw new Error('AI2 queries bos geldi');

const weakWords = [
  'kurumsal',
  'buyuk olcekli',
  'holding',
  'firma',
  'isletme',
  'sirketler grubu'
];

const mustNeg = [
  '-yazilim',
  '-software',
  '-saas',
  '-danismanlik',
  '-entegrator',
  '-ajans',
  '-platform',
  '-cozum',
  '-vendor'
];

const out = [];
const seen = new Set();
const dropped = [];

for (const q of arr) {
  const segment = String(q.segment || '').trim();
  let query = String(q.query || '').trim();
  const used = (Array.isArray(q.used_keywords) ? q.used_keywords : [])
    .map(x => String(x || '').trim())
    .filter(Boolean);

  if (!query || !/site:linkedin\.com\/company/i.test(query)) {
    dropped.push('linkedin format eksik');
    continue;
  }

  const nQuery = normTr(query);
  if (weakWords.some(w => nQuery.includes(w))) {
    dropped.push('zayif ifade bulundu');
    continue;
  }

  if (!/\bTurkiye\b/i.test(query)) {
    query += ' Turkiye';
  }

  if (used.length >= 2) {
    const missing = used.filter(k => !new RegExp(`"${esc(k)}"`, 'i').test(query));
    if (missing.length) {
      query += ' (' + missing.map(k => `"${k}"`).join(' OR ') + ')';
    }
  }

  const low = query.toLowerCase();
  for (const n of mustNeg) {
    if (!low.includes(n)) query += ' ' + n;
  }

  const key = query.toLowerCase().replace(/\s+/g, ' ').trim();
  if (seen.has(key)) continue;
  seen.add(key);

  out.push({
    json: {
      segment: segment || 'N/A',
      query,
      must_terms: used
    }
  });
}

if (out.length < 6) {
  throw new Error(`AI2 kalitesi dusuk. Gecerli query: ${out.length}, elenen: ${dropped.length}`);
}

return out.slice(0, 12);

const response = $json;

if (response.error || response.httpCode) {
  return [];
}

const today = new Date().toISOString().slice(0, 10);
const q = String((response.search_parameters && response.search_parameters.q) || '').toLowerCase();
const mustTerms = [...q.matchAll(/"([^"]+)"/g)]
  .map(m => m[1].toLowerCase().trim())
  .filter(t => t.length >= 3);

const providerWords = [
  'yazilim', 'software', 'saas', 'danismanlik', 'consulting', 'entegrator',
  'agency', 'ajans', 'cozum ortagi', 'platform', 'vendor', 'solution provider'
];

const results = Array.isArray(response.organic_results) ? response.organic_results : [];
const seen = new Set();
const out = [];

for (const r of results) {
  const link = String(r.link || '').trim();
  if (!/linkedin\.com\/company\//i.test(link)) continue;
  if (/\/jobs\/|\/people\/|\/school\/|\/posts\/|\/events\//i.test(link)) continue;

  const text = (String(r.title || '') + ' ' + String(r.snippet || '')).toLowerCase();

  let providerHit = false;
  for (const w of providerWords) {
    if (text.includes(w)) {
      providerHit = true;
      break;
    }
  }
  if (providerHit) continue;

  let overlap = 0;
  for (const t of mustTerms) {
    if (text.includes(t)) overlap++;
  }
  if (mustTerms.length > 0 && overlap === 0) continue;

  const norm = link.replace(/\/$/, '').toLowerCase();
  if (seen.has(norm)) continue;
  seen.add(norm);

  const title = String(r.title || 'N/A')
    .replace(/\s*\|\s*linkedin.*$/i, '')
    .replace(/\s*-\s*linkedin.*$/i, '')
    .trim();

  out.push({
    json: {
      business_name: title || 'N/A',
      website: link,
      snippet: String(r.snippet || 'N/A').trim(),
      email: 'Not found',
      phone: 'Not found',
      position: String(r.position || out.length + 1),
      scraped_date: today,
      address: String(r.displayed_link || 'LinkedIn'),
      rating: '',
      reviews: '',
      relevance_score: overlap
    }
  });
}

return out;

const inItems = $input.all();
const out = [];
const seen = new Set();

for (const item of inItems) {
  const row = item.json || {};
  const score = Number(row.relevance_score || 0);
  if (score < 1) continue;

  const key = String(row.website || '').replace(/\/$/, '').toLowerCase();
  if (!key || seen.has(key)) continue;
  seen.add(key);

  delete row.relevance_score;
  out.push({ json: row });
}

if (out.length === 0) {
  throw new Error('Filtre sonrasi uygun musteri adayi kalmadi. Queryler fazla genis veya urun metni yetersiz.');
}

return out;
